/**
 * Diff Review Panel - Webview Script
 * Handles diff rendering and comment interactions
 */
(function() {
  'use strict';

  // Get VSCode API
  const vscode = acquireVsCodeApi();

  // State
  let currentData = null;
  let comments = [];

  // Restore previous state if available
  const previousState = vscode.getState();
  if (previousState) {
    currentData = previousState.currentData || null;
    comments = previousState.comments || [];
  }

  /**
   * Save current state for persistence
   */
  function saveState() {
    vscode.setState({
      currentData,
      comments,
      scrollPosition: window.scrollY
    });
  }

  // Notify extension we're ready
  vscode.postMessage({ type: 'ready' });

  // Handle messages from extension
  window.addEventListener('message', event => {
    const message = event.data;

    switch (message.type) {
      case 'loadDiff':
        currentData = message.data;
        renderDiff(message.data);
        saveState();
        break;
      case 'themeChanged':
        updateTheme(message.theme);
        break;
      case 'updateComments':
        comments = message.comments || [];
        renderComments(comments);
        saveState();
        break;
    }
  });

  // Restore scroll position after content loads
  if (previousState && previousState.scrollPosition) {
    requestAnimationFrame(() => {
      window.scrollTo(0, previousState.scrollPosition);
    });
  }

  /**
   * Render the diff content
   * Placeholder implementation - diff2html integration in WI-04
   */
  function renderDiff(data) {
    const container = document.getElementById('diff-container');

    if (!data.baseline && !data.accumulated) {
      container.innerHTML = `
        <div class="empty-state">
          <div class="icon">📄</div>
          <p>No changes to display</p>
        </div>
      `;
      return;
    }

    // Calculate simple stats
    const baselineLines = (data.baseline || '').split('\n').length;
    const accumulatedLines = (data.accumulated || '').split('\n').length;
    const diff = accumulatedLines - baselineLines;

    // Update stats in toolbar
    const statsEl = document.getElementById('stats');
    if (statsEl) {
      if (diff >= 0) {
        statsEl.innerHTML = `<span class="additions">+${diff} lines</span>`;
      } else {
        statsEl.innerHTML = `<span class="deletions">${diff} lines</span>`;
      }
    }

    // Placeholder diff display
    // This will be replaced with diff2html in WI-04
    const baselinePreview = truncate(data.baseline || 'No baseline content', 1000);
    const accumulatedPreview = truncate(data.accumulated || 'No accumulated content', 1000);

    container.innerHTML = `
      <div class="placeholder-diff">
        <h3>Original (Baseline)</h3>
        <pre>${escapeHtml(baselinePreview)}</pre>
        <hr>
        <h3>Current (After Claude Edits)</h3>
        <pre>${escapeHtml(accumulatedPreview)}</pre>
      </div>
      <p style="color: var(--vscode-descriptionForeground); text-align: center; margin-top: 24px;">
        Full diff rendering will be available after diff2html integration (WI-04)
      </p>
    `;
  }

  /**
   * Update the theme class on body
   */
  function updateTheme(theme) {
    document.body.className = theme;
  }

  /**
   * Render comments
   * Placeholder implementation - full UI in WI-05
   */
  function renderComments(comments) {
    // Will be implemented in WI-05
    console.log('Comments to render:', comments);
  }

  /**
   * Escape HTML special characters
   */
  function escapeHtml(text) {
    if (!text) return '';
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }

  /**
   * Truncate text with ellipsis
   */
  function truncate(text, maxLength) {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '\n... (truncated)';
  }

  /**
   * Post a message to the extension
   */
  function postMessage(type, data) {
    vscode.postMessage({ type, ...data });
  }

  // Expose functions for future use
  window.diffReview = {
    postMessage,
    renderDiff,
    renderComments
  };
})();
